esqlQuery.esql:
FROM logs-myservicereceiver.otel-*
// Flag each log entry as an error or not
| EVAL is_error = CASE(log.level == "error", 1, 0)
// Aggregate total logs and error count per service
| STATS total = COUNT(*), errors = SUM(is_error) BY service.name
// Minimum sample size to avoid noisy low-traffic services
// Adjust this threshold based on expected traffic volume
| WHERE total > 50
// Calculate error rate as a percentage
| EVAL error_rate_pct = ROUND(errors / total * 100.0, 2)
// Alert threshold: adjust this to tune sensitivity
| WHERE error_rate_pct > 5.0
| SORT error_rate_pct DESC
| LIMIT 10
